    // Handle deprecated autoRemoveTarget option
    if (definition?.autoRemoveTarget) {
        console.warn(
            "Koota: 'autoRemoveTarget' is deprecated. Use 'autoDestroy: \"orphan\"' instead."
        );
        autoDestroy = 'source';
